const raw = $input.first().json;
const text = raw.text ?? '';
const tags = raw.tags ?? [];
const visibility = raw.visibility ?? 'public';
const spoilerText = raw.spoiler_text ?? null;
if (!text) throw new Error('Skill Mastodon: text is required');
const tagStr = tags.map(t => '#' + t.replace(/\s+/g, '')).join(' ');
const status = (text + (tagStr ? '\n\n' + tagStr : '')).slice(0, 500);
return [{ json: { status, visibility, spoiler_text: spoilerText } }];

const result = $input.item.json;
const url = result.url ?? null;
return [{ json: { status: url ? 'success' : 'failed', toot_url: url, result_summary: url ? `Posted to Mastodon: ${url}` : 'Mastodon post failed' } }];
